ps.pstext:
if !IsFeatureImplemented(FEAT_SVE_B16B16) then EndOfDecode(Decode_UNDEF); end;

let g : integer = UInt(Pg);
let dn : integer = UInt(Zdn);
let m : integer = UInt(Zm);

if IsFeatureImplemented(FEAT_SME2) then CheckSVEEnabled(); else CheckNonStreamingSVEEnabled(); end;
let VL : integer{} = CurrentVL();
let PL : integer{} = VL DIV 8;
let elements : integer = VL DIV 16;
let mask : bits(PL) = P{}(g);
let operand1 : bits(VL) = Z{}(dn);
let operand2 : bits(VL) = if AnyActiveElement{PL}(mask, 16) then Z{VL}(m) else Zeros{VL};
var result : bits(VL);

for e = 0 to elements-1 do
    let element1 : bits(16) = operand1[e*:16];
    if ActivePredicateElement{PL}(mask, e, 16) then
        let element2 : bits(16) = operand2[e*:16];
        result[e*:16] = BFMinNum{16}(element1, element2, FPCR());
    else
        result[e*:16] = element1;
    end;
end;

Z{VL}(dn) = result;
